import { LibSQLVector } from "@mastra/libsql";
import { MDocument } from "@mastra/rag";
import { Mastra } from "@mastra/core";
import { openai } from "@ai-sdk/openai";
import { embedMany, embed, generateText } from "ai";
import * as fs from "fs";
import * as dotenv from "dotenv";

dotenv.config();

async function main() {
  const filePath = "/home/user/myproject/data.md";
  const logPath = "/home/user/myproject/output.log";

  // 1. Read markdown file
  const content = fs.readFileSync(filePath, "utf-8");

  // 2. Chunk the document
  const doc = MDocument.fromMarkdown(content);
  const chunks = await doc.chunk({
    strategy: "recursive",
    size: 512,
    overlap: 50,
  });

  console.log(`Created ${chunks.length} chunks`);

  // 3. Generate embeddings
  const { embeddings } = await embedMany({
    values: chunks.map((chunk) => chunk.text),
    model: openai.embedding("text-embedding-3-small"),
  });

  // 4. Store in local vector store (LibSQL)
  const vectorStore = new LibSQLVector({
    id: "my-vector-store",
    url: "file:/home/user/myproject/mastra.db",
  });

  const indexName = "main_index";

  // Create index if it doesn't exist
  try {
    await vectorStore.createIndex({
      indexName,
      dimension: 1536, // dimension for text-embedding-3-small
    });
  } catch (e) {
    console.log("Index might already exist");
  }

  await vectorStore.upsert({
    indexName,
    vectors: embeddings,
    metadata: chunks.map((chunk) => ({ text: chunk.text })),
  });

  // 5. Query the vector store
  const question = "What is the main topic of the document?";

  const { embedding: queryVector } = await embed({
    value: question,
    model: openai.embedding("text-embedding-3-small"),
  });

  const results = await vectorStore.query({
    indexName,
    queryVector,
    topK: 3,
  });

  const context = results.map((r) => r.metadata.text).join("\n\n");

  // 6. Get final LLM answer
  const { text: answer } = await generateText({
    model: openai("gpt-4o-mini"),
    prompt: `Answer the following question based on the provided context:

Question: ${question}

Context:
${context}

Answer:`,
  });

  // 7. Output to log file
  fs.writeFileSync(logPath, answer);
  console.log(`Result written to ${logPath}`);
  console.log(`Answer: ${answer}`);
}

main().catch(console.error);

